def normalize_extension_name(name: str) -> str:
    if name is None:
        raise ValueError("Extension name is required")
    name = name.strip()
    if not name:
        raise ValueError("Extension name is required")
    if not EXTENSION_NAME_RE.match(name):
        raise ValueError("Invalid extension name. Use letters, numbers, underscores; must not start with a number.")
    return name


def install_extension(conn, extension_name: str, schema: str = None, if_not_exists: bool = True):
    ext = normalize_extension_name(extension_name)
    parts = [
        sql.SQL("CREATE EXTENSION "),
        sql.SQL("IF NOT EXISTS ") if if_not_exists else sql.SQL(""),
        sql.Identifier(ext),
    ]
